let velocityY = 0;
let velocityX = 0;
let isGrounded = false;
let coinsCollected = 0;
let lives = 3;
const moveSpeed = 5;
const jumpPower = 15;
const platformData = {
  'Ground': {x: 0, y: 280, w: 800, h: 40},
  'Platform1': {x: -150, y: 180, w: 200, h: 20},
  'Platform2': {x: 150, y: 180, w: 200, h: 20},
  'Platform3': {x: 0, y: 80, w: 200, h: 20}
};

// Input
let moveX = 0;
if (Input.isKeyPressed('a')) moveX -= moveSpeed;
if (Input.isKeyPressed('d')) moveX += moveSpeed;
velocityX = moveX;

// Jump
if (Input.isKeyPressed(' ') && isGrounded) {
  velocityY = -jumpPower;
  isGrounded = false;
}

// Apply gravity
velocityY += 0.5;

// Update position
self.x += velocityX;
self.y += velocityY;

// Collision with platforms
isGrounded = false;
for (let platformName in platformData) {
  const p = platformData[platformName];
  const px = p.x;
  const py = p.y;
  const pw = p.w;
  const ph = p.h;
  const playerW = 20;
  const playerH = 30;

  if (self.x + playerW/2 > px - pw/2 && 
      self.x - playerW/2 < px + pw/2 &&
      self.y + playerH/2 > py - ph/2 &&
      self.y - playerH/2 < py + ph/2) {
    // Landing on top
    if (velocityY > 0 && self.y + playerH/2 - velocityY <= py - ph/2) {
      self.y = py - ph/2 - playerH/2;
      velocityY = 0;
      isGrounded = true;
    }
  }
}

// Boundary check - fall off screen
if (self.y > 400) {
  lives -= 1;
  if (lives <= 0) {
    state.gameOver = true;
  }
  self.x = 0;
  self.y = 150;
  velocityY = 0;
}

// Check coin collisions
for (let i = 1; i <= 5; i++) {
  const coinName = 'Coin' + i;
  const coin = entities.get(coinName);
  if (coin) {
    const dx = coin.x - self.x;
    const dy = coin.y - self.y;
    const distance = Math.sqrt(dx*dx + dy*dy);
    if (distance < 20) {
      coinsCollected += 1;
      coin.collected = true;
      entities.delete(coinName);
    }
  }
}

// Check goomba collisions
for (let i = 1; i <= 3; i++) {
  const goombaName = 'Goomba' + i;
  const goomba = entities.get(goombaName);
  if (goomba) {
    const dx = goomba.x - self.x;
    const dy = goomba.y - self.y;
    const distance = Math.sqrt(dx*dx + dy*dy);
    if (distance < 25) {
      lives -= 1;
      if (lives <= 0) {
        state.gameOver = true;
      }
      self.x = 0;
      self.y = 150;
      velocityY = 0;
    }
  }
}

// Update UI
const ui = entities.get('UI');
if (ui) {
  ui.text = 'Coins: ' + coinsCollected + ' | Lives: ' + lives;
}

let patrolDirection = 1;
let speed = 2;

self.x += patrolDirection * speed;

if (self.x > 350 || self.x < -350) {
  patrolDirection *= -1;
}

